import React, { useState, useEffect, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { ModelProvider, MarketType, AnalysisResult, MainBoardScanItem } from '../types';
import { fetchMainBoardScanning } from '../services/geminiService';
import { Gavel, Loader2, Search, ArrowRight, Activity, Zap, Target, Flame, ShieldAlert, BarChart3, Rocket, Lock, Share2, Skull, RefreshCw, ZapOff, Trophy, Filter, ArrowUpDown, Layers, LayoutGrid, List, ChevronDown, ChevronUp, Crown, Star, Network } from 'lucide-react';

export const MainBoardMaster: React.FC<{
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: any;
  onOpenSettings: () => void;
}> = ({ currentModel, currentMarket, settings, onOpenSettings }) => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [elapsed, setElapsed] = useState(0);
  const [viewMode, setViewMode] = useState<'list' | 'sector'>('sector');

  // Sorting state
  const [sortKey, setSortKey] = useState<keyof MainBoardScanItem>('consecutive_days');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');

  useEffect(() => {
    let interval: any;
    if (loading) {
      setElapsed(0);
      interval = setInterval(() => setElapsed(p => p + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleScan = async () => {
    if (!settings.geminiKey) {
      onOpenSettings();
      return;
    }
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await fetchMainBoardScanning(settings.geminiKey);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "主板扫描失败，请检查网络或 API 配置");
    } finally {
      setLoading(false);
    }
  };

  const handleNavigateToStock = (code: string, name: string) => {
    navigate(`/stock?q=${encodeURIComponent(code + " " + name)}`);
  };

  const toggleSort = (key: keyof MainBoardScanItem) => {
    if (sortKey === key) {
      setSortOrder(sortOrder === 'desc' ? 'asc' : 'desc');
    } else {
      setSortKey(key);
      setSortOrder('desc');
    }
  };

  const scanData = result?.mainBoardScanData;

  // Sector Grouping & Ladder Analysis Logic
  const sectorAnalysis = useMemo(() => {
    if (!scanData?.stocks) return null;

    const groups: Record<string, MainBoardScanItem[]> = {};
    scanData.stocks.forEach(stock => {
      const s = stock.sector || '其他';
      if (!groups[s]) groups[s] = [];
      groups[s].push(stock);
    });

    return Object.entries(groups).map(([name, stocks]) => {
      // Sort stocks in sector by consecutive days desc
      const sorted = [...stocks].sort((a, b) => b.consecutive_days - a.consecutive_days);
      const counts: Record<number, number> = {};
      stocks.forEach(s => {
        counts[s.consecutive_days] = (counts[s.consecutive_days] || 0) + 1;
      });

      // Calculate ladder integrity
      const uniqueDays = Object.keys(counts).map(Number).sort((a, b) => b - a);
      const isLadderIntact = uniqueDays.length >= 3; // e.g. 5-3-1 exists
      const maxDays = uniqueDays[0] || 0;
      const leader = sorted[0];

      return {
        name,
        stocks: sorted,
        count: stocks.length,
        maxDays,
        uniqueDays,
        isLadderIntact,
        leader,
        ladderSummary: uniqueDays.map(d => `${d}板(${counts[d]})`).join(' → ')
      };
    }).sort((a, b) => {
      // Prioritize sectors with more limit-ups and better ladders
      if (b.count !== a.count) return b.count - a.count;
      return b.maxDays - a.maxDays;
    });
  }, [scanData]);

  const sortedStocks = useMemo(() => {
    if (!scanData?.stocks) return [];
    return [...scanData.stocks].sort((a, b) => {
      const valA = a[sortKey];
      const valB = b[sortKey];
      if (typeof valA === 'number' && typeof valB === 'number') {
        return sortOrder === 'desc' ? valB - valA : valA - valB;
      }
      if (typeof valA === 'string' && typeof valB === 'string') {
        return sortOrder === 'desc' ? valB.localeCompare(valA) : valA.localeCompare(valB);
      }
      return 0;
    });
  }, [scanData, sortKey, sortOrder]);

  const getRatingIcon = (rating: string) => {
    switch (rating) {
      case '起爆': return <Rocket className="w-4 h-4 text-rose-500" />;
      case '锁筹': return <Lock className="w-4 h-4 text-amber-500" />;
      case '分歧': return <Share2 className="w-4 h-4 text-blue-500" />;
      case '出货': return <Skull className="w-4 h-4 text-slate-500" />;
      default: return <Gavel className="w-4 h-4 text-emerald-500" />;
    }
  };

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-rose-600 bg-rose-50 border-rose-100 font-black';
    if (score >= 60) return 'text-amber-600 bg-amber-50 border-amber-100 font-bold';
    return 'text-slate-500 bg-slate-50 border-slate-100 font-medium';
  };

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto pb-20">
      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8 md:p-10 relative overflow-hidden">
        <div className="relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
            <div>
              <h2 className="text-3xl font-black text-slate-800 flex items-center gap-4 mb-2">
                <div className="p-3 bg-gradient-to-br from-emerald-600 to-emerald-800 rounded-2xl text-white shadow-xl shadow-emerald-100">
                  <Gavel className="w-8 h-8" />
                </div>
                沪深主板涨停猎手
              </h2>
              <p className="text-slate-500 text-base max-w-2xl font-medium">
                实时扫描 A 股主板涨停标的，独家算法识别 **板块梯队 (Sector Ladder)** 与 **市场龙头 (Dragon Leader)**。
              </p>
            </div>

            <button 
              onClick={handleScan}
              disabled={loading}
              className="px-10 h-16 bg-emerald-600 text-white rounded-[1.5rem] font-black shadow-2xl hover:bg-emerald-700 transition-all flex items-center gap-3 active:scale-95 disabled:opacity-50"
            >
              {loading ? <Loader2 className="w-6 h-6 animate-spin" /> : <Rocket className="w-6 h-6" />}
              {loading ? `主板梯队深度审计中 (${elapsed}s)...` : '今日沪深涨停全扫描'}
            </button>
          </div>

          <div className="flex flex-wrap gap-4 items-center">
            <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200 no-print">
               <button onClick={() => setViewMode('sector')} className={`px-4 py-1.5 text-xs font-black rounded-lg transition-all flex items-center gap-2 ${viewMode === 'sector' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
                  <LayoutGrid className="w-3.5 h-3.5" /> 板块梯队视图
               </button>
               <button onClick={() => setViewMode('list')} className={`px-4 py-1.5 text-xs font-black rounded-lg transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
                  <List className="w-3.5 h-3.5" /> 纯列表视图
               </button>
            </div>
            <div className="h-4 w-px bg-slate-200 mx-2 hidden md:block"></div>
            <div className="flex items-center gap-2 px-4 py-2 bg-emerald-50 border border-emerald-100 rounded-xl text-emerald-700 text-xs font-black">
