                  <div className="text-[10px] text-slate-400 font-bold">按涨停标的数量与高度排序</div>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {sectorAnalysis.map((sector, idx) => (
                    <div key={idx} className={`bg-white rounded-[2rem] border-2 transition-all hover:shadow-xl group flex flex-col h-full ${sector.isLadderIntact ? 'border-emerald-500 shadow-emerald-50 bg-emerald-50/5' : 'border-slate-100 shadow-sm'}`}>
                       <div className="p-8 pb-4">
                          <div className="flex justify-between items-start mb-4">
                             <div className="flex flex-col">
                                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">活跃板块</span>
                                <h4 className="text-2xl font-black text-slate-800">{sector.name}</h4>
                             </div>
                             <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-xl shadow-inner ${sector.isLadderIntact ? 'bg-emerald-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                                {sector.count}
                             </div>
                          </div>

                          <div className="flex items-center gap-2 mb-6">
                             {sector.isLadderIntact ? (
                               <div className="flex items-center gap-1.5 px-3 py-1.5 bg-emerald-100 text-emerald-700 text-[10px] font-black rounded-lg border border-emerald-200">
                                  <Flame className="w-3.5 h-3.5" /> 梯队完整·强势主线
                               </div>
                             ) : (
                               <div className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-100 text-slate-500 text-[10px] font-black rounded-lg border border-slate-200">
                                  <Activity className="w-3.5 h-3.5" /> 梯队断档·关注补涨
                               </div>
                             )}
                          </div>

                          <div className="bg-white/50 border border-slate-100 rounded-2xl p-4 mb-6">
                             <div className="text-[9px] font-black text-slate-400 uppercase mb-2">梯队阵列 (Ladder)</div>
                             <div className="text-sm font-black text-slate-700 tracking-tighter">
                                {sector.ladderSummary}
                             </div>
                          </div>

                          <div className="space-y-3">
                             <div className="text-[9px] font-black text-slate-400 uppercase px-1 flex items-center gap-2">
                                <Crown className="w-3 h-3 text-amber-500" /> 该题材龙一标的
                             </div>
                             <div 
                               onClick={() => handleNavigateToStock(sector.leader.code, sector.leader.name)}
                               className="p-4 bg-slate-900 text-white rounded-2xl border border-slate-800 shadow-lg cursor-pointer hover:bg-slate-800 transition-all flex justify-between items-center group/leader"
                             >
                                <div>
                                   <div className="font-black text-lg flex items-center gap-2">
                                      {sector.leader.name}
                                      <Star className="w-3 h-3 text-amber-400 fill-amber-400" />
                                   </div>
                                   <div className="text-[10px] font-mono text-slate-400">{sector.leader.code}</div>
                                </div>
                                <div className="text-right">
                                   <div className="text-xl font-black text-rose-500">{sector.leader.consecutive_days}连板</div>
                                   <div className="text-[9px] font-bold text-slate-500 group-hover/leader:text-white transition-colors">深度分析 →</div>
                                </div>
                             </div>
                          </div>
                       </div>

                       <div className="mt-auto p-4 px-8 border-t border-slate-100 flex flex-wrap gap-2">
                          {sector.stocks.slice(1, 4).map((s, si) => (
                             <span key={si} className="text-[10px] font-bold text-slate-500 bg-slate-50 px-2 py-1 rounded-lg border border-slate-100">
                                {s.name} ({s.consecutive_days}B)
                             </span>
                          ))}
                          {sector.count > 4 && <span className="text-[10px] font-bold text-slate-300">+{sector.count - 4}只...</span>}
                       </div>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {/* Market Sentiment Summary (Simplified version of the old one) */}
