/**
 * Perform a general analysis using Gemini
 */
export const fetchGeminiAnalysis = async (prompt: string, isComplex: boolean = false, apiKey?: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = isComplex ? GEMINI_MODEL_PRO : GEMINI_MODEL_PRIMARY;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      thinkingConfig: isComplex ? { thinkingBudget: 4000 } : undefined
    }
  });

  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: false
  };
};

/**
 * Fetch a structured market dashboard
 */
export const fetchMarketDashboard = async (period: 'day' | 'month', market: MarketType, apiKey?: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const dateStr = new Date().toLocaleDateString('zh-CN');

  const prompt = `Analyze the ${market} market for the ${period === 'day' ? 'current day' : 'current month'} as of ${dateStr}. 
  Provide detailed index data, volume analysis, sentiment, and capital rotation.`;

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: marketDashboardSchema
    }
  });

  const parsed = robustParse(response.text || "{}");
  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    structuredData: parsed,
    market
  };
};

